import{_ as i,c as r,o as t,a5 as e,j as a}from"./chunks/framework.Dtwt352Q.js";const _=JSON.parse('{"title":"v1.1.27：修复桌面端体验问题","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.27.md","filePath":"changelog/v1.1.27.md","lastUpdated":1772014034000}'),h={name:"changelog/v1.1.27.md"};function d(n,l,o,s,c,p){return t(),r("div",null,[...l[0]||(l[0]=[e('<h1 id="v1-1-27-修复桌面端体验问题" tabindex="-1">v1.1.27：修复桌面端体验问题 <a class="header-anchor" href="#v1-1-27-修复桌面端体验问题" aria-label="Permalink to “v1.1.27：修复桌面端体验问题”">​</a></h1><p><strong>发布日期</strong>：2026年01月20日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>修复了桌面应用启动闪屏、消息列表滚动、配置持久化等问题，使用体验更流畅。</p><hr><h2 id="改进-修复桌面端体验问题" tabindex="-1">改进：修复桌面端体验问题 <a class="header-anchor" href="#改进-修复桌面端体验问题" aria-label="Permalink to “改进：修复桌面端体验问题”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>桌面应用在使用过程中可能会遇到一些小问题：</p><ul><li>启动时偶尔闪一下首页</li><li>消息列表滚动时可能溢出或卡顿</li><li>配额限制设置在刷新后会丢失</li><li>不小心缩放页面导致布局混乱</li></ul><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>这些问题都已修复，桌面应用现在更稳定、更流畅：</p><ul><li>✅ 启动不再闪屏，直接进入工作状态</li><li>✅ 消息列表滚动流畅，不再溢出</li><li>✅ 配额限制会持久保存，刷新不丢失</li><li>✅ 完全禁用了桌面端的缩放功能，避免误触</li></ul><hr><h2 id="新功能-选择项目目录文本" tabindex="-1">新功能：选择项目目录文本 <a class="header-anchor" href="#新功能-选择项目目录文本" aria-label="Permalink to “新功能：选择项目目录文本”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在你可以在桌面应用中直接选择并复制项目目录的路径文本了。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>打开桌面应用</li><li>在项目设置或会话信息中找到项目目录路径</li><li>点击路径文本即可选中复制</li></ol><hr><h2 id="问题修复-mcp-服务器截断处理" tabindex="-1">问题修复：MCP 服务器截断处理 <a class="header-anchor" href="#问题修复-mcp-服务器截断处理" aria-label="Permalink to “问题修复：MCP 服务器截断处理”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>当 MCP 服务器返回大量内容时，可能会出现截断处理不当的情况。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在 MCP 服务器的截断处理更加可靠，长内容不会意外丢失。</p><hr><h2 id="问题修复-tui-内存泄漏" tabindex="-1">问题修复：TUI 内存泄漏 <a class="header-anchor" href="#问题修复-tui-内存泄漏" aria-label="Permalink to “问题修复：TUI 内存泄漏”">​</a></h2><h3 id="之前的问题-2" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-2" aria-label="Permalink to “之前的问题”">​</a></h3><p>在 TUI（终端界面）模式下使用一段时间后，内存占用会不断增加。</p><h3 id="现在的情况-2" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-2" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了消息历史清理逻辑，现在会正确释放不再需要的消息，防止内存泄漏。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>桌面应用用户</td><td>✅ 强烈推荐，修复了多个体验问题</td></tr><tr><td>TUI 用户</td><td>✅ 推荐，修复了内存泄漏</td></tr><tr><td>刚升了 v1.1.26</td><td>可以等下次，但升了也没坏处</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',35),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),e('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><p><strong>核心功能 (Core)</strong></p><ul><li>移除 patch 工具中的文件时间断言</li><li>确保 MCP 服务器的截断处理正确应用</li><li>更新 batch 工具定义，明确最大工具调用值</li></ul><p><strong>TUI</strong></p><ul><li>在工具选择提示中添加空格切换提示</li><li>修复消息历史清理以防止 TUI 中的内存泄漏</li></ul><p><strong>桌面端 (Desktop)</strong></p><ul><li>修复应用启动时的首页闪屏问题</li><li>修复应用中的 localStorage 配额处理</li><li>持久化配额限制以防止刷新后丢失</li><li>完全禁用桌面应用中的缩放功能</li><li>修复消息列表溢出和滚动问题</li><li>为最近会话弹出框添加 8px 内边距</li><li>移除编辑项目对话框表单的顶部内边距</li><li>更新会话消息弹出框的间距为 28px</li><li>将会话消息弹出框定位在顶部</li><li>当弹出框打开时保留会话悬停状态并更新边框半径</li><li>更新会话悬停弹出框样式</li><li>更新审查会话空状态样式</li><li>添加在 Web 界面中选择项目目录文本的功能</li></ul><p><strong>感谢 5 位社区贡献者</strong></p></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=i(h,[["render",d]]);export{_ as __pageData,m as default};
